class Solution {
public:
    string decodeString(string s) {
        string ans;
        int i = 0;
        while (i < s.length()) {
            if (isdigit(s[i])) {
                int mult = 0;
                while (isdigit(s[i])) {
                    mult = mult * 10 + (s[i] - '0');
                    i++;
                }
                i++;
                int fbracket = 1;
                int start = i;
                while (fbracket != 0) {
                    if (s[i] == '[') fbracket++;
                    if (s[i] == ']') fbracket--;
                    i++;
                }
                string temp = decodeString(s.substr(start, i - start - 1));
                for (int j = 0; j < mult; j++) {
                    ans += temp;
                }
            } else {
                ans += s[i];
                i++;
            }
        }
        return ans;
    }
};
